function createBankAccount(ownerName, initialBalance) {
  let balance = initialBalance; // PRIVATE — not accessible outside
  const transactions = [];       // PRIVATE — full history hidden

  return {
    deposit(amount) {
      if (amount <= 0) throw new Error('Amount must be positive');
      balance += amount;
      transactions.push({ type: 'deposit', amount });
    },
    withdraw(amount) {
      if (amount > balance) throw new Error('Insufficient funds');
      balance -= amount;
      transactions.push({ type: 'withdrawal', amount });
    },
    getBalance() { return balance; },           // controlled read
    getStatement() { return [...transactions]; } // returns a copy, not the live array
  };
}

const account = createBankAccount('Alice', 1000);
account.deposit(500);
account.withdraw(200);
console.log(account.getBalance()); // 1300
console.log(account.balance);      // undefined — truly private

